      if (!c || c.monthIdx !== new Date().getMonth()) return 0;
      const today = new Date();
      const idx = c.data.weeks.findIndex(w => w.dates.some(d => d.day === today.getDate() && d.month === today.getMonth() + 1));
      return idx >= 0 ? idx : 0;
